201 /// This class augments VPValue with operands which provide the inverse def-use
202 /// edges from VPValue's users to their defs.
203 class VPUser {
204 public:
205   /// Subclass identifier (for isa/dyn_cast).
206   enum class VPUserID {
207     Recipe,
208     LiveOut,
209   };
210 
211 private:
